import argparse
from kafka.admin import AdminClient, NewTopic

def create_topic(admin_client, topic_name, num_partitions=1, replication_factor=1):
    new_topic = NewTopic(name=topic_name, num_partitions=num_partitions, replication_factor=replication_factor)
    futures = admin_client.create_topics([new_topic])
    for topic, future in futures.items():
        try:
            future.result()
            print(f"Topic {topic} created successfully.")
        except Exception as e:
            print(f"Failed to create topic {topic}: {e}")

def manage_partitions(admin_client, topic_name, new_partition_count):
    admin_client.alter_topic_configs(
        topic_name,
        {'num.partitions': str(new_partition_count)}
    )
    print(f"Partition count for topic {topic_name} updated to {new_partition_count}.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Kafka cluster administration script.")
    parser.add_argument("action", choices=["create_topic", "manage_partitions"], help="Action to perform")
    parser.add_argument("topic_name", help="Name of the topic")
    parser.add_argument("--num_partitions", type=int, default=1, help="Number of partitions (for create_topic)")
    parser.add_argument("--new_partition_count", type=int, help="New partition count (for manage_partitions)")

    args = parser.parse_args()

    admin_client = AdminClient(bootstrap_servers=["your_kafka_broker_address"])

    if args.action == "create_topic":
        create_topic(admin_client, args.topic_name, num_partitions=args.num_partitions)
    elif args.action == "manage_partitions":
        manage_partitions(admin_client, args.topic_name, new_partition_count=args.new_partition_count)

admin_client.close()